117	    ///
118	    /// Returns `None` if the ring buffer is empty.
119	    fn try_peek(&self) -> Option<&Self::Item> {
120	        if !self.is_empty() {
121	            Some(unsafe { self.occupied_slices().0.get_unchecked(0).assume_init_ref() })
