7	
8	pub const NO_WAIT: Option<Duration> = Some(Duration::ZERO);
9	pub const FOREVER: Option<Duration> = None;
10	
11	/// Elapsed time counter.
12	pub trait Instant {
13	    fn now() -> Self;
14	    fn elapsed(&self) -> Duration;
15	}
16	
17	/// Binary semaphore.
18	pub trait Semaphore: Default {
19	    type Instant: Instant;
20	
21	    /// Increment semaphore.
22	    ///
23	    /// Does nothing if already given.
24	    fn give(&self);
25	
26	    /// Try decrement semaphore.
27	    ///
28	    /// Returns previous value.
29	    ///
30	    /// Does nothing if already taken.
31	    fn try_take(&self) -> bool;
32	
33	    /// Wait for semaphore to be given and take it.
34	    ///
35	    /// Returns:
36	    /// + on success - `true`,
37	    /// + on timeout - `false`.
38	    fn take(&self, timeout: Option<Duration>) -> bool;
39	
40	    fn take_iter(&self, timeout: Option<Duration>) -> TakeIter<'_, Self> {
41	        TakeIter {
42	            reset: false,
43	            semaphore: self,
44	            timeout_iter: TimeoutIter::new(timeout),
45	        }
46	    }
47	}
