49	#[cfg(feature = "std")]
50	pub use std::time::Instant as StdInstant;
51	
52	#[cfg(feature = "std")]
53	impl Instant for StdInstant {
54	    fn now() -> Self {
55	        StdInstant::now()
56	    }
57	    fn elapsed(&self) -> Duration {
58	        StdInstant::elapsed(self)
59	    }
60	}
61	
62	#[cfg(feature = "std")]
63	#[derive(Default)]
64	pub struct StdSemaphore {
65	    condvar: Condvar,
66	    mutex: Mutex<bool>,
67	}
68	
69	#[cfg(feature = "std")]
70	impl Semaphore for StdSemaphore {
71	    type Instant = StdInstant;
72	
73	    fn give(&self) {
74	        let mut guard = self.mutex.lock().unwrap();
75	        *guard = true;
76	        self.condvar.notify_one();
77	    }
78	
79	    fn try_take(&self) -> bool {
80	        replace(&mut self.mutex.lock().unwrap(), false)
81	    }
82	    fn take(&self, timeout: Option<Duration>) -> bool {
83	        let mut guard = self.mutex.lock().unwrap();
84	        for timeout in TimeoutIter::<Self::Instant>::new(timeout) {
85	            if replace(&mut guard, false) {
86	                return true;
87	            }
88	            match timeout {
89	                Some(t) => {
90	                    let r;
91	                    (guard, r) = self.condvar.wait_timeout(guard, t).unwrap();
92	                    if r.timed_out() {
93	                        break;
94	                    }
95	                }
96	                None => guard = self.condvar.wait(guard).unwrap(),
97	            };
98	        }
99	        replace(&mut guard, false)
100	    }
101	}
102	
103	#[derive(Clone, Debug)]
104	pub struct TimeoutIter<I: Instant> {
105	    start: I,
106	    timeout: Option<Duration>,
107	}
108	
109	impl<I: Instant> TimeoutIter<I> {
110	    pub fn new(timeout: Option<Duration>) -> Self {
111	        Self { start: I::now(), timeout }
112	    }
113	}
114	
115	impl<I: Instant> Iterator for TimeoutIter<I> {
116	    type Item = Option<Duration>;
117	    fn next(&mut self) -> Option<Self::Item> {
118	        match self.timeout {
119	            Some(dur) => {
120	                let elapsed = self.start.elapsed();
121	                if dur > elapsed {
122	                    Some(Some(dur - elapsed))
123	                } else {
124	                    None
125	                }
126	            }
127	            None => Some(None),
128	        }
129	    }
130	}
131	
132	pub struct TakeIter<'a, X: Semaphore> {
133	    reset: bool,
134	    semaphore: &'a X,
135	    timeout_iter: TimeoutIter<X::Instant>,
136	}
137	
138	impl<X: Semaphore> Iterator for TakeIter<'_, X> {
139	    type Item = ();
